#include <iostream>
#include <string>
#include <string_view>

int main() {
    std::string line{};
    std::getline(std::cin, line);
    std::string_view sv{ line };

    std::size_t leading{ sv.find_first_not_of(' ') };
    if (leading != std::string_view::npos)
        sv.remove_prefix(leading);

    std::size_t last{ sv.find_last_not_of(' ') };
    if (last != std::string_view::npos)
        sv.remove_suffix(sv.size() - last - 1);

    std::cout << sv << '\n';
    return 0;
}

